mapper.select:
SELECT id, name, invite_code, created_at, updated_at
FROM families
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

SELECT id, name, invite_code, created_at, updated_at
FROM families
WHERE invite_code = #{inviteCode}

mapper.update:
UPDATE families
SET name = #{name},
    invite_code = #{inviteCode},
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
